import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { studentsAPI, violationsAPI } from '../../services/api';
import Card from '../../components/common/Card';
import toast from 'react-hot-toast';
import { Search, AlertTriangle, Send } from 'lucide-react';

const EncodeViolation = () => {
  const { user } = useAuth();
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedStudent, setSelectedStudent] = useState(null);
  const [submitting, setSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    violationType: '',
    remarks: '',
    date: new Date().toISOString().split('T')[0]
  });

  const violationTypes = [
    'Minor Offense - Tardiness',
    'Minor Offense - Improper Uniform',
    'Minor Offense - Cutting Classes',
    'Major Offense - Disrespectful Behavior',
    'Major Offense - Academic Dishonesty',
    'Major Offense - Vandalism',
    'Major Offense - Fighting',
    'Major Offense - Theft',
    'Other'
  ];

  const searchStudents = async () => {
    if (!searchTerm) return;

    setLoading(true);
    try {
      const response = await studentsAPI.getAll({ search: searchTerm });
      if (response.data.success) {
        setStudents(response.data.students);
      }
    } catch (error) {
      console.error('Error searching students:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!selectedStudent) {
      toast.error('Please select a student');
      return;
    }
    if (!formData.violationType || !formData.date) {
      toast.error('Please fill all required fields');
      return;
    }

    setSubmitting(true);
    try {
      await violationsAPI.create({
        studentId: selectedStudent.id,
        violationType: formData.violationType,
        remarks: formData.remarks,
        date: formData.date
      });
      toast.success('Violation recorded successfully');
      setSelectedStudent(null);
      setFormData({
        violationType: '',
        remarks: '',
        date: new Date().toISOString().split('T')[0]
      });
      setSearchTerm('');
      setStudents([]);
    } catch (error) {
      toast.error('Failed to record violation');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <h1 className="text-2xl font-bold text-secondary-800">Encode Violation</h1>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Student Search */}
        <Card title="Search Student">
          <div className="space-y-4">
            <div className="flex gap-2">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-secondary-400" />
                <input
                  type="text"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && searchStudents()}
                  placeholder="Search by name or student ID..."
                  className="input-field pl-10"
                />
              </div>
              <button
                onClick={searchStudents}
                disabled={loading}
                className="btn-primary"
              >
                {loading ? 'Searching...' : 'Search'}
              </button>
            </div>

            {/* Search Results */}
            {students.length > 0 && (
              <div className="border border-secondary-200 rounded-lg divide-y divide-secondary-100 max-h-64 overflow-y-auto">
                {students.map((student) => (
                  <button
                    key={student.id}
                    onClick={() => {
                      setSelectedStudent(student);
                      setStudents([]);
                      setSearchTerm('');
                    }}
                    className={`w-full text-left p-3 hover:bg-secondary-50 transition-colors ${
                      selectedStudent?.id === student.id ? 'bg-primary-50' : ''
                    }`}
                  >
                    <p className="font-medium text-secondary-800">
                      {student.first_name} {student.last_name}
                    </p>
                    <p className="text-sm text-secondary-500">
                      {student.student_id} | {student.year_level} - {student.section}
                    </p>
                  </button>
                ))}
              </div>
            )}

            {/* Selected Student */}
            {selectedStudent && (
              <div className="bg-primary-50 border border-primary-200 rounded-lg p-4">
                <h4 className="font-medium text-primary-800 mb-2">Selected Student</h4>
                <p className="text-primary-700">
                  {selectedStudent.first_name} {selectedStudent.last_name}
                </p>
                <p className="text-sm text-primary-600">
                  ID: {selectedStudent.student_id} | {selectedStudent.year_level} - {selectedStudent.section}
                </p>
                <button
                  onClick={() => setSelectedStudent(null)}
                  className="text-sm text-red-600 hover:text-red-700 mt-2"
                >
                  Remove selection
                </button>
              </div>
            )}
          </div>
        </Card>

        {/* Violation Form */}
        <Card title="Violation Details">
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="label">Violation Type *</label>
              <select
                value={formData.violationType}
                onChange={(e) => setFormData(prev => ({ ...prev, violationType: e.target.value }))}
                className="input-field"
                required
              >
                <option value="">Select Violation Type</option>
                {violationTypes.map((type) => (
                  <option key={type} value={type}>{type}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="label">Date of Incident *</label>
              <input
                type="date"
                value={formData.date}
                onChange={(e) => setFormData(prev => ({ ...prev, date: e.target.value }))}
                className="input-field"
                required
              />
            </div>

            <div>
              <label className="label">Remarks</label>
              <textarea
                value={formData.remarks}
                onChange={(e) => setFormData(prev => ({ ...prev, remarks: e.target.value }))}
                rows={4}
                placeholder="Additional details about the violation..."
                className="input-field"
              />
            </div>

            <button
              type="submit"
              disabled={submitting || !selectedStudent}
              className="w-full btn-primary flex items-center justify-center gap-2"
            >
              <Send className="w-4 h-4" />
              {submitting ? 'Recording...' : 'Record Violation'}
            </button>
          </form>
        </Card>
      </div>
    </div>
  );
};

export default EncodeViolation;
